public class Discount {
    static final double REGULAR_DISCOUNT = 10.0;
    static final double PREMIUM_DISCOUNT = 20.0;
    static final double VIP_DISCOUNT = 30.0;

    public static void main(String[] args) {
        System.out.println("Regular: " + calculate(1000, "regular"));
        System.out.println("Premium: " + calculate(1000, "premium"));
        System.out.println("VIP: " + calculate(1000, "vip"));
    }

    public static double calculate(double price, String tier) {
        double discountRate;

        if (tier.equals("vip")) {
            discountRate = VIP_DISCOUNT;
        } else if (tier.equals("premium")) {
            discountRate = PREMIUM_DISCOUNT;
        } else {
            discountRate = REGULAR_DISCOUNT;
        }

        return price - (price * discountRate / 100);
    }
}

public class Bank {
    static final double INTEREST_RATE = 5.0;
    static int totalAccounts = 0;

    public static void main(String[] args) {
        createAccount("Aisha", 5000.0);
        createAccount("Raj", 10000.0);
        createAccount("Priya", 2500.0);
        System.out.println("Total accounts: " + totalAccounts);
        System.out.println("Interest on ₹10000.0: ₹" + calculateInterest(10000.0));
    }

    public static void createAccount(String owner, double initialDeposit) {
        int accountId = totalAccounts + 1;
        totalAccounts++;
        System.out.println("Account #" + accountId + " created for " + owner + " with ₹" + initialDeposit);
    }

    public static double calculateInterest(double balance) {
        return balance * INTEREST_RATE / 100;
    }
}

