public class Inventory {
    static final int MAX_ITEMS_PER_ORDER = 100;
    static final int MIN_STOCK_THRESHOLD = 10;

    static int currentStock = 50;
    static int totalOrdersProcessed = 0;

    public static void main(String[] args) {
        boolean result1 = processOrder(30);
        System.out.println("Order 30: " + (result1 ? "Success" : "Failed") + ". Stock: " + currentStock);

        boolean result2 = processOrder(25);
        System.out.println("Order 25: " + (result2 ? "Success" : "Failed") + ". Stock: " + currentStock);

        boolean result3 = processOrder(15);
        System.out.println("Order 15: " + (result3 ? "Success" : "Failed") + ". Stock: " + currentStock);

        System.out.println("Total orders processed: " + totalOrdersProcessed);
        System.out.println("Low stock alert: " + checkLowStock());
    }

    public static boolean processOrder(int quantity) {
        if (quantity > MAX_ITEMS_PER_ORDER) {
            return false;
        }
        if (quantity > currentStock) {
            return false;
        }
        currentStock -= quantity;
        totalOrdersProcessed++;
        return true;
    }

    public static boolean checkLowStock() {
        return currentStock < MIN_STOCK_THRESHOLD;
    }
}
